To accomplish this, we will use the **RCSB PDB Search API** (to find the IDs) and the **Data API** (to fetch metadata). 

### Prerequisites
You will need `requests`, `pandas`, and `matplotlib`. Install them via:
`pip install requests pandas matplotlib`

### Python Script

```python
import requests
import pandas as pd
import matplotlib.pyplot as plt
import time

# 1. Define the GraphQL query to fetch structure metadata
def get_pdb_metadata():
    query = """
    {
      entries(entry_ids: []) {
        rcsb_id
        rcsb_entry_info { resolution_combined }
        exptl { method }
        polymer_entities {
          rcsb_entity_source_organism { scientific_name }
          uniprot_ids
          rcsb_polymer_entity_container_identifiers { auth_asym_ids }
        }
      }
    }
    """
    # Note: For large datasets, use the Search API first to get IDs, 
    # then batch fetch metadata.
    search_url = "https://search.rcsb.org/rcsbsearch/v2/query?json="
    search_query = {
        "query": {
            "type": "terminal",
            "service": "text",
            "parameters": {"value": "SARS-CoV-2"}
        },
        "return_type": "entry"
    }

    response = requests.post(search_url, json=search_query).json()
    ids = response.get("result_set", [])[:100] # Limiting for demo purposes

    data = []
    # Mapping UniProt IDs to Gene Names
    gene_map = {
        "P0DTC2": "Spike", "P0DTC1": "NSP1", "P0DTC3": "NSP3", 
        "P0DTC4": "NSP4", "P0DTC5": "NSP5", "P0DTC6": "NSP6",
        "P0DTC7": "NSP7", "P0DTC8": "NSP8", "P0DTC9": "NSP9",
        "P0DTD1": "NSP10", "P0DTD2": "NSP11", "P0DTD3": "NSP12",
        "P0DTD4": "NSP13", "P0DTD5": "NSP14", "P0DTD6": "NSP15",
        "P0DTD7": "NSP16", "P0DTC9": "N", "P0DTC5": "E", "P0DTC4": "M"
    }

    for pdb_id in ids:
        # Respecting Rate Limits
        time.sleep(0.2) 
        url = f"https://data.rcsb.org/rest/v1/core/entry/{pdb_id['identifier']}"
        res = requests.get(url).json()

        try:
            res_val = res['rcsb_entry_info']['resolution_combined'][0]
            method = res['exptl'][0]['method']

            for entity in res.get('polymer_entities', []):
                u_ids = entity.get('uniprot_ids', [])
                if u_ids:
                    for u_id in u_ids:
                        if u_id in gene_map:
                            data.append({
                                "PDB_ID": pdb_id['identifier'],
                                "Resolution": res_val,
                                "Method": method,
                                "Gene": gene_map[u_id]
                            })
        except (KeyError, TypeError):
            continue

    return pd.DataFrame(data)

# 2. Process and Tabulate
df = get_pdb_metadata()
summary = df.groupby('Gene').agg({'PDB_ID': 'count', 'Resolution': 'mean'}).rename(
    columns={'PDB_ID': 'Count', 'Resolution': 'Mean_Resolution'}
)

print(summary)

# 3. Visualization
summary['Count'].plot(kind='bar', color='skyblue', figsize=(10, 6))
plt.title('SARS-CoV-2 Structure Coverage per Gene')
plt.ylabel('Number of Structures')
plt.xlabel('Gene')
plt.tight_layout()
plt.show()
```

### Key Considerations:
1.  **Rate Limiting**: The script uses `time.sleep(0.2)` to ensure we do not overwhelm the RCSB API. For production-scale data (thousands of structures), consider using the RCSB Bulk Data download (via S3 or PDB flat files) rather than individual REST calls.
2.  **Gene Mapping**: The script maps UniProt accessions to gene names. SARS-CoV-2 proteins often share UniProt entries (e.g., the polyprotein), so the mapping logic in the script is simplified for demonstration. You may need to cross-reference with the [RCSB PDB entity mapping](https://www.rcsb.org/docs/programmatic-access/file-and-data-downloads) for more granular protein identification.
3.  **Data Cleaning**: It filters for structures with available resolution data (`resolution_combined`). Note that NMR structures will return `None` or empty lists for resolution; you may want to filter `Method == 'X-RAY DIFFRACTION'` if you specifically require resolution metrics.

To accomplish this, we will use the **RCSB PDB Search API** (to find the IDs) and the **Data API** (to fetch the metadata via GraphQL, which is more efficient than REST for deep queries).

### Prerequisites
You will need `requests`, `pandas`, and `matplotlib` installed:
```bash
pip install requests pandas matplotlib
```

### Python Script

```python
import requests
import pandas as pd
import matplotlib.pyplot as plt
import time

# 1. Define GraphQL Query to fetch metadata
QUERY = """
{
  entries(entry_ids: []) {
    rcsb_id
    rcsb_entry_info { resolution_combined }
    exptl { method }
    polymer_entities {
      rcsb_entity_source_organism { scientific_name }
      uniprot_ids
      rcsb_polymer_entity_container_identifiers { auth_asym_ids }
    }
  }
}
"""

def fetch_sars_cov_2_data():
    # Step 1: Search for SARS-CoV-2 structures
    search_url = "https://search.rcsb.org/rcsbsearch/v2/query"
    search_query = {
        "query": {
            "type": "terminal",
            "service": "text",
            "parameters": {"value": "SARS-CoV-2"}
        },
        "return_type": "entry"
    }

    response = requests.post(search_url, json=search_query)
    pdb_ids = response.json()['result_set'][:100] # Limiting to 100 for demo speed

    # Step 2: Fetch metadata using GraphQL
    graphql_url = "https://data.rcsb.org/graphql"
    data = []

    for i in range(0, len(pdb_ids), 10): # Rate limiting/chunking
        batch = [x['identifier'] for x in pdb_ids[i:i+10]]
        query = QUERY.replace("[]", str(batch).replace("'", '"'))

        resp = requests.post(graphql_url, json={'query': query})
        for entry in resp.json()['data']['entries']:
            for entity in entry['polymer_entities']:
                # Filter for SARS-CoV-2 entities
                if any("SARS-CoV-2" in org['scientific_name'] for org in entity['rcsb_entity_source_organism']):
                    data.append({
                        "pdb_id": entry['rcsb_id'],
                        "resolution": entry['rcsb_entry_info']['resolution_combined'][0] if entry['rcsb_entry_info']['resolution_combined'] else None,
                        "method": entry['exptl'][0]['method'] if entry['exptl'] else "N/A",
                        "uniprot": entity['uniprot_ids'][0] if entity['uniprot_ids'] else None
                    })
        time.sleep(0.5) # Respectful delay
    return pd.DataFrame(data)

# 3. Map UniProt to Genes (Simplified mapping based on SARS-CoV-2 context)
def map_gene(uniprot_id):
    mapping = {
        'P0DTC2': 'Spike', 'P0DTC1': 'NSP1', 'P0DTD1': 'NSP2', 'P0DTD2': 'NSP3',
        'P0DTD3': 'NSP4', 'P0DTD4': 'NSP5', 'P0DTD5': 'NSP6', 'P0DTD6': 'NSP7',
        'P0DTD8': 'NSP8', 'P0DTD9': 'NSP9', 'P0DTE0': 'NSP10', 'P0DTE3': 'NSP12',
        'P0DTE7': 'NSP13', 'P0DTE8': 'NSP14', 'P0DTE9': 'NSP15', 'P0DTC7': 'NSP16',
        'P0DTC9': 'N', 'P0DTC4': 'E', 'P0DTC5': 'M'
    }
    return mapping.get(uniprot_id, 'Other')

# Execution
df = fetch_sars_cov_2_data()
df['gene'] = df['uniprot'].apply(map_gene)

# 4. Coverage Table
coverage = df.groupby('gene').agg({'pdb_id': 'count', 'resolution': 'mean'}).rename(columns={'pdb_id': 'count'})
print(coverage)

# 5. Visualization
coverage['count'].plot(kind='bar', color='skyblue', title='SARS-CoV-2 Structure Coverage by Gene')
plt.ylabel('Number of Structures')
plt.tight_layout()
plt.show()
```

### Key Considerations:
1.  **Rate Limiting:** The script uses `time.sleep(0.5)` and fetches data in batches of 10 to ensure we do not overwhelm the RCSB API.
2.  **GraphQL Efficiency:** Instead of making hundreds of REST calls for individual PDB files, we use the GraphQL endpoint to fetch metadata for multiple structures in a single request.
3.  **Mapping:** The `map_gene` function uses canonical UniProt IDs for the SARS-CoV-2 reference proteome.
4.  **Data Cleaning:** The script handles missing resolution values (common in NMR structures) by checking the return list from the API before accessing the index.
